SELECT [Sales Shipment Header].No_, Sum(Val([Sales Shipment Line.Quantity])) AS qtyShipped, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Quantity]))) AS qtyInvoiced, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([sales invoice line.Amount]))) AS Amount_, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Line Discount Amount]))) AS LineDiscountAmount, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Line Amount]))) AS LineAmount, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Inv_ Discount Amount]))) AS InvoiceDiscountAmountu, [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [Sales Shipment Header].[Posting Date] AS DataSpedzione, [Sales Shipment Line].[DDT No_], [FattureRegistrateEDdt-step0].[posted no_], [FattureRegistrateEDdt-step0].TransportDescription, [FattureRegistrateEDdt-step0].OnlyTransfer, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header].[No_]) AS InvoiceNo_, IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header.Posting Date]) AS DataFattura, [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2
FROM (((([Sales Invoice Line] LEFT JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) RIGHT JOIN (([Sales Shipment Line] LEFT JOIN [Sales Shipment Header] ON [Sales Shipment Line].[Document No_] = [Sales Shipment Header].No_) LEFT JOIN [Sales Header] ON [Sales Shipment Line].[Order No_] = [Sales Header].No_) ON ([Sales Invoice Line].[Shipment Line No_] = [Sales Shipment Line].[Line No_]) AND ([Sales Invoice Line].[Shipment No_] = [Sales Shipment Line].[Document No_])) LEFT JOIN (Customer LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) ON [Sales Shipment Line].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) RIGHT JOIN [FattureRegistrateEDdt-step0] ON [Sales Shipment Line].[DDT No_] = [FattureRegistrateEDdt-step0].No_
GROUP BY [Sales Shipment Header].No_, [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [Sales Shipment Header].[Posting Date], [Sales Shipment Line].[DDT No_], [FattureRegistrateEDdt-step0].[posted no_], [FattureRegistrateEDdt-step0].TransportDescription, [FattureRegistrateEDdt-step0].OnlyTransfer, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header].[No_]), IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header.Posting Date]), [Geographical Zone].Description, [Geographical Zone_1].Description, [Sales Shipment Line].Type
HAVING (((Sum(Val([Sales Shipment Line.Quantity])))<>0) AND (([Sales Shipment Line].Type)=2));

